CREATE TABLE IF NOT EXISTS rng ("date" DATE, "user" VARCHAR(50), "rank" INT NOT NULL, score INT NOT NULL, first_seen INT NOT NULL, last_seen INT NOT NULL, CONSTRAINT pk_rng PRIMARY KEY ("date", "user"), CONSTRAINT fk_rng_user__name FOREIGN KEY ("user") REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_rng_first_seen__id FOREIGN KEY (first_seen) REFERENCES requests(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_rng_last_seen__id FOREIGN KEY (last_seen) REFERENCES requests(id) ON DELETE RESTRICT ON UPDATE RESTRICT);